/**
 * SubscribeButton
 *
 * Email subscription button with optional inline input + validation.
 * You provide `onSubscribe(email)`; the component manages the small UI state
 * machine (idle → loading → success/error).
 *
 * @example
 * ```tsx
 * <SubscribeButton onSubscribe={(email) => api.subscribe(email)}>
 *   Subscribe
 * </SubscribeButton>
 * ```
 */

'use client';
import * as React from 'react';
import Alert from '@mui/material/Alert';
import Button from '@mui/material/Button';
import type { ButtonProps } from '@mui/material/Button';
import CircularProgress from '@mui/material/CircularProgress';
import Snackbar from '@mui/material/Snackbar';
import Stack from '@mui/material/Stack';
import TextField from '@mui/material/TextField';
import MailOutlineIcon from '@mui/icons-material/MailOutline';
import CheckCircleIcon from '@mui/icons-material/CheckCircle';

/** Props for {@link SubscribeButton}. */
export interface SubscribeButtonProps extends Omit<ButtonProps, 'onClick'> {
  onSubscribe: (email: string) => Promise<boolean>;
  placeholder?: string;
  successMessage?: string;
  errorMessage?: string;
  requireEmail?: boolean;
  showInlineForm?: boolean;
}

const SubscribeButton: React.FC<SubscribeButtonProps> = ({
  onSubscribe,
  placeholder = 'Enter your email address',
  successMessage = 'Successfully subscribed!',
  errorMessage = 'Subscription failed. Please try again.',
  requireEmail = true,
  showInlineForm = true,
  children = 'Subscribe',
  ...rest
}) => {
  const [email, setEmail] = React.useState('');
  const [isLoading, setIsLoading] = React.useState(false);
  const [showSuccess, setShowSuccess] = React.useState(false);
  const [showError, setShowError] = React.useState(false);
  const [emailError, setEmailError] = React.useState('');

  const validateEmail = (email: string): boolean => {
    const emailRegex = /^[^\s@]+@[^\s@]+\.[^\s@]+$/;
    return emailRegex.test(email);
  };

  const handleSubscribe = async () => {
    if (requireEmail && !email.trim()) {
      setEmailError('Email address is required');
      return;
    }

    if (requireEmail && !validateEmail(email)) {
      setEmailError('Please enter a valid email address');
      return;
    }

    setEmailError('');
    setIsLoading(true);

    try {
      const success = await onSubscribe(email);
      if (success) {
        setShowSuccess(true);
        setEmail('');
      } else {
        setShowError(true);
      }
    } catch {
      setShowError(true);
    } finally {
      setIsLoading(false);
    }
  };

  if (showInlineForm) {
    return (
      <>
        <Stack direction={{ xs: 'column', sm: 'row' }} spacing={1} sx={{ width: '100%' }}>
          <TextField
            value={email}
            onChange={(e) => {
              setEmail(e.target.value);
              setEmailError('');
            }}
            placeholder={placeholder}
            error={Boolean(emailError)}
            helperText={emailError}
            type="email"
            fullWidth
            size="medium"
          />
          <Button
            onClick={handleSubscribe}
            disabled={isLoading}
            startIcon={isLoading ? <CircularProgress size={20} /> : <MailOutlineIcon />}
            sx={{ minWidth: 140 }}
            {...rest}
          >
            {isLoading ? 'Subscribing...' : children}
          </Button>
        </Stack>

        <Snackbar open={showSuccess} autoHideDuration={4000} onClose={() => setShowSuccess(false)}>
          <Alert severity="success" icon={<CheckCircleIcon />}>
            {successMessage}
          </Alert>
        </Snackbar>

        <Snackbar open={showError} autoHideDuration={4000} onClose={() => setShowError(false)}>
          <Alert severity="error">{errorMessage}</Alert>
        </Snackbar>
      </>
    );
  }

  return (
    <Button
      onClick={handleSubscribe}
      disabled={isLoading}
      startIcon={isLoading ? <CircularProgress size={20} /> : <MailOutlineIcon />}
      {...rest}
    >
      {isLoading ? 'Subscribing...' : children}
    </Button>
  );
};

export default SubscribeButton;
